solution: ```class CombinationIterator {
    vector<string> combos;
    int idx = 0;
public:
    CombinationIterator(string characters, int combinationLength) {
        string cur;
        dfs(characters, combinationLength, 0, cur);
    }

    void dfs(const string& s, int len, int start, string& cur) {
        if (cur.size() == len) {
            combos.push_back(cur);
            return;
        }
        for (int i = start; i < s.size(); ++i) {
            cur.push_back(s[i]);
            dfs(s, len, i + 1, cur);
            cur.pop_back();
        }
    }

    string next() {
        return combos[idx++];
    }

    bool hasNext() {
        return idx < combos.size();
    }
};
```
efficiency: HIGH
time complexity: O(2^n) for constructor, O(1) for next and hasNext
space complexity: O(C(n,k)) where C(n,k) is the number of combinations
energy implications: MEDIUM
explanation: Pre-generate all combinations via DFS once during construction; subsequent calls are O(1). Efficient for up to 15 characters and 10^4 queries.

